export type OrderState = "pending" | "paid" | "shipped" | "cancelled";

// Returns whether the order can still be cancelled by the customer.
export function isCancellable(state: OrderState): boolean {
  switch (state) {
    case "pending":
      return true;
    case "paid":
      return true;
    case "shipped":
      return false;
  }
}
